      function CF_20Formula return Char is
V_DURATION VARCHAR2(50);

cursor c_lixi_ergasias is
select a.value
from pen_dec_fact_types_instance a
where a.di_document_type_dec_coce_sr = '1'  
and   a.status 			                 = '1'
and   a.ins_insured_id               = :p_insured_id 
and   a.di_dec_incr_seq_no_sr        = :p_dec_incr_sec_no_sr 
and   a.di_decision_year_sr          = :p_dt_decision_year 
and   a.di_dec_unit_code_sr          = :p_dt_dec_unit_code 
and   a.title_code                   in ( '00635','01635' )  --- ΕΡΓΑΣΙΑ (ΑΠΟ 13/05/2016)
and   a.dec_fact_type_code           = '00588'               --- ΛΗΞΗ ΕΡΓΑΣΙΑΣ
and   a.value	IS NOT NULL
;
l_lixi_ergasias varchar2(12);


begin

  open  c_lixi_ergasias;
  fetch c_lixi_ergasias into l_lixi_ergasias;
  close c_lixi_ergasias;
  
  IF  l_lixi_ergasias IS NOT NULL AND TO_DATE(l_lixi_ergasias,'DD/MM/YYYY') < :P_PENSION_START_DATE THEN ---MAIL BY CHRYS 04/12/2023 
  	
    RETURN NULL;
  
  ELSE
		  v_DURATION := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
							 0,:p_form_id,'00001','01635','00637');
			
			IF V_DURATION IS NULL THEN
		  	v_DURATION := Find_Fact_Sub_Death_Varchar(:P_Insured_Id,:P_DT_DECISION_YEAR,:P_DT_DEC_UNIT_CODE,:P_DEC_INCR_SEC_NO_SR, '1',
							 0,:p_form_id,'00001','00635','00637');
			END IF;
		
		--COMBAT_dEBUGING('v_DURATION = '||v_DURATION, 'CHRYS_REPORTS');
		return v_DURATION;
  END IF;
  
  EXCEPTION WHEN OTHERS THEN RETURN NULL;
END;

