      function M_8FormatTrigger return boolean is
/* CHRYS 9/6/2021 
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;

begin
  -- G?? ???GOG?S ??? ????? G?? ????S??S ???? 1/1/2019
  V_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019
  INTO V_2019;
	CLOSE CUR_2019;
	  
  IF V_2019 = '1' THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;
end;
END CHRYS 9/6/2021 */
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;

-- CHRYS 1/7/2021
CURSOR CUR_CONV_START_DATE IS
SELECT START_dATE
FROM PEN_ACCOUNT
WHERE ACCOUNT_NO = :CP_CONV_ACCOUNT;

V_CONV_START_dATE		DATE;
-- END CHRYS 1/7/2021

begin
  -- CHRYS 1/7/2021
  OPEN	CUR_CONV_START_DATE;
  FETCH	CUR_CONV_START_DATE
  INTO  V_CONV_START_dATE ;
  CLOSE	CUR_CONV_START_DATE;
  -- END CHRYS 1/7/2021

  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	
	IF :P_IS_OGA = 1  --- ΟΤΑΝ ΥΠΑΓΩΓΗ = ΟΓΑ ΤΟΤΕ ΝΑ ΕΜΦΑΝΙΖΕΤΑΙ ΠΑΝΤΑ MAIL 19/07/2021 ΝΤ & ΤΜΗΜΑ ΝΟΜΟΘΕΣΙΑΣ ΜΗ ΜΙΣΘΩΤΩΝ
		THEN RETURN (TRUE);
	ELSE
	  IF NVL(V_01_01_2019,'0') = '1' OR 
	  	( NVL(V_01_10_2019,'0') = '1' 
	  	AND :cp_award_TYPE != '8') -- CHRYS 9/6/2021 
	  	THEN
	  	return (FALSE);
		-- CHRYS 1/7/2021
		ELSIF NVL(V_01_10_2019,'0') = '1' AND :cp_award_TYPE = '8' AND V_CONV_START_dATE >= TO_DATE('01/01/2019','DD/MM/RRRR') THEN
	  	return (FALSE);
	 	-- END CHRYS 1/7/2021 	
	  ELSE
	  	return (TRUE);
	  END IF;
  END IF;
  
  return (TRUE);
end;

      function CF_PROD_DESCFormula return Char is
V_RET VARCHAR2(200);

CURSOR C1 IS
Select DECODE(A.DOCUMENT_CODE,'003', 'ΣΥΝΤΑΞΗ ΑΝΑΠΗΡΙΑΣ'
	                           ,'002', 'ΣΥΝΤΑΞΗ ΓΗΡΑΤΟΣ')
From Pen_Award_Type_Flag_Desc A,
     Wrk_In_Out B
Where A.Document_Code        = B.Document_Code
  And B.Protocol_Orgbra_Code = :P_APPL_UNIT_CODE
  And B.Protocol_Year        = :P_APPL_YEAR
  And B.Protocol_No          = :P_APPL_INCR_SEQ_NO
; 


begin

	OPEN C1;
	  FETCH C1 INTO V_RET;
	CLOSE C1;
	  
	RETURN V_RET;
	
	EXCEPTION WHEN OTHERS THEN RETURN NULL;
end;

