      function M_66FormatTrigger return boolean is
/* CHRYS 9/6/2021  CUR_2019 IS
SELECT AFTER_01_01_2019_FLG FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019
  V_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019
  INTO V_2019;
	CLOSE CUR_2019;
	  
  IF V_2019 = '1' THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;
end;
END CHRYS 9/6/2021 */
CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;


begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 - Η ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/10/2019
  V_01_01_2019 := '0';
  V_01_10_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019,V_01_10_2019;
	CLOSE CUR_2019;
	  
  IF NVL(V_01_01_2019,'0') = '1' OR 
  	( NVL(V_01_10_2019,'0') = '1' 
  	AND :cp_award_flag != '8') -- CHRYS 9/6/2021
  	--OR (:CF_35='00008' AND :P_FACTITIOUS_DATE >= TO_DATE('01/01/2019','DD/MM/YYYY'))
  	THEN
  	return (FALSE);
  ELSE
  	return (TRUE);
  END IF;

  return (TRUE);

END ;

