      function M_69FormatTrigger return boolean is

CURSOR CUR_2019 IS
SELECT AFTER_01_01_2019_FLG, AFTER_01_10_2019_FLG, QUAL_FLG 
FROM PEN_INTRODUCTIONS
WHERE INTRODUCTION_CODE = :CF_35;

V_01_01_2019    PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_01_10_2019    PEN_INTRODUCTIONS.AFTER_01_10_2019_FLG%TYPE;

V_2019          PEN_INTRODUCTIONS.AFTER_01_01_2019_FLG%TYPE;
V_QUAL_FLG      PEN_INTRODUCTIONS.QUAL_FLG%TYPE;

begin
  -- ΓΙΑ ΥΠΑΓΩΓΕΣ ΠΟΥ ΕΙΝΑΙ ΓΙΑ ΑΙΤΗΣΕΙΣ ΜΕΤΑ 1/1/2019 Η ΜΕΤΑ 1/10/2019 
  
  V_2019 := '0';
  
  OPEN CUR_2019;
  FETCH CUR_2019 INTO V_01_01_2019, V_01_10_2019, V_QUAL_FLG;
	CLOSE CUR_2019;

IF NVL(V_QUAL_FLG,'0')  = '1' THEN   --- 26/10/2021 SPAP EPEIDI OSES YPAGOGES THEMELIONOUN DEN EXOYN ANAGH NA SYMBRILOROUN TIS EIDIKES PLIROFORIES ETH-MHNES-HMERES
	RETURN (FALSE); 
ELSE	
	IF NVL(V_01_01_2019,'0') = '1' OR NVL(V_01_10_2019,'0') = '1' 
		THEN V_2019 := '1';
  END IF;

  if :cf_35 in ('00010','00011')
  then
     return (TRUE);
  end if;

  IF V_2019 = '1' THEN
  	return (TRUE);
  ELSE
  	return (FALSE);
  END IF;

  return (TRUE);
END IF;
return (TRUE);
end;

