      function CF_EPIDOMA_ANIKANFormula return Number is
-- CHRYS 10/11/2022
V_EPIDOMA		NUMBER;

CURSOR	CUR_EPIDOMA IS
SELECT AMOUNT
FROM   PEN_QT_PER_BE_CC_PER_ACCOUNT A,
			 PEN_ACCOUNT B
WHERE  B.ACCOUNT_NO = :P_ACC_ACCOUNT_NO
AND    B.ACCOUNT_NO = A.ACC_ACCOUNT_NO
AND    A.CP_CALCULATION_PARAMETER_CODE = 'EANIK';
			 
begin

OPEN	CUR_EPIDOMA;
FETCH	CUR_EPIDOMA
INTO	V_EPIDOMA;
CLOSE	CUR_EPIDOMA;

RETURN (NVL(V_EPIDOMA,0));

END ;

